// // This module implements an 8-bit register with asynchronous reset. When reset is deasserted, the output q should be 0.
module reg8 (
    input clk,
    input reset,
    input [7:0] d,
    output reg [7:0] q);always @(posedge clk) begin
    if (reset)
        q <= 8'b0;
    else
        q <= d;
end
endmodule
